class Solution {
public:
    vector<int> numsSameConsecDiff(int n, int k) {
        vector<int> res;
        for (int i = 1; i <= 9; ++i) {
            dfs(i, 1, n, k, res);
        }
        return res;
    }

    void dfs(long long cur, int len, int n, int k, vector<int>& res) {
        if (len == n) {
            res.push_back(cur);
            return;
        }
        int lastDigit = cur % 10;
        if (lastDigit - k >= 0) {
            dfs(cur * 10 + lastDigit - k, len + 1, n, k, res);
        }
        if (lastDigit + k <= 9 && k != 0) {
            dfs(cur * 10 + lastDigit + k, len + 1, n, k, res);
        }
    }
};
```
